const martResult = $input.first().json;
const prev = $('Build Mart Request').first().json;
const plan = prev.plan;
const stgData = $('Create Staging Tables').first().json;
const mart = martResult.mart_table || {};
const stmts = [];
// Drop the existing mart before recreating it so CREATE TABLE IF NOT EXISTS is not a no-op
if (plan.mart_table_name) stmts.push('DROP TABLE IF EXISTS ' + plan.mart_table_name);
if (mart.ddl) stmts.push(mart.ddl);
if (mart.populate_sql) mart.populate_sql.split(';').map(s => s.trim()).filter(s => s).forEach(s => stmts.push(s));
stgData.staging_tables.forEach(t => stmts.push('DROP TABLE IF EXISTS ' + t.name));
return [{
  json: {
    mart_cleanup_statements: stmts,
    mart_table: mart,
    vault_tables: prev.vault_tables,
    plan: plan
  }
}];

