const prev = $('Collect Mart + Cleanup').first().json;
const plan = prev.plan;
const martName = plan.mart_table_name;
const retryCount = prev.retry_count || 0;

return (async () => {
  const database = '/data/vault.duckdb';
  const baseUrl = 'http://duckdb-service:8001/query';

  // Check 1: row count
  const countRes = await this.helpers.httpRequest({
    method: 'POST', url: baseUrl,
    headers: { 'content-type': 'application/json' },
    body: { sql: 'SELECT COUNT(*) AS cnt FROM ' + martName, database },
    json: true,
  });
  const rowCount = countRes.rows?.[0]?.cnt || 0;

  if (rowCount === 0) {
    return [{ json: { valid: false, retry_count: retryCount, error: 'Mart table is empty (0 rows)', plan, mart_table: prev.mart_table, vault_tables: prev.vault_tables } }];
  }

  // Check 2: sample rows for NULL dimension columns
  const sampleRes = await this.helpers.httpRequest({
    method: 'POST', url: baseUrl,
    headers: { 'content-type': 'application/json' },
    body: { sql: 'SELECT * FROM ' + martName + ' LIMIT 10', database },
    json: true,
  });

  const rows = sampleRes.rows || [];
  const columns = sampleRes.columns || [];

  // Find columns where ALL sampled values are null (excluding mart_insert_dts and numeric metrics)
  const nullCols = [];
  for (const col of columns) {
    if (col === 'mart_insert_dts') continue;
    const allNull = rows.every(r => r[col] === null || r[col] === undefined);
    if (allNull && rows.length > 0) nullCols.push(col);
  }

  if (nullCols.length > 0) {
    return [{ json: { 
      valid: false, 
      retry_count: retryCount,
      error: 'Mart has all-NULL columns: ' + nullCols.join(', ') + '. The JOIN to populate these columns likely used mismatched keys. Ensure all JOINs between hub, satellite, and link tables use matching hash keys (_hk columns).',
      null_columns: nullCols,
      plan, 
      mart_table: prev.mart_table, 
      vault_tables: prev.vault_tables 
    } }];
  }

  return [{ json: { valid: true, retry_count: retryCount, plan, mart_table: prev.mart_table, vault_tables: prev.vault_tables } }];
})();

const prev = $input.first().json;
const retryCount = prev.retry_count || 0;

return (async () => {
  if (retryCount >= 1) {
    // Already retried once, give up and let DQ Agent handle it
    return [{ json: { valid: true, skip_retry: true, plan: prev.plan, mart_table: prev.mart_table, vault_tables: prev.vault_tables } }];
  }

  // Build enhanced mart request with error feedback
  const martRequest = {
    vault_tables: prev.vault_tables,
    mart_table_name: prev.plan.mart_table_name,
    grain: prev.plan.grain,
    metrics: prev.plan.metrics || [],
    business_keys: prev.plan.business_keys || [],
    previous_error: prev.error,
    retry_instructions: 'The previous mart SQL produced NULL values in columns: ' + (prev.null_columns || []).join(', ') + '. This is because the JOINs used mismatched keys. IMPORTANT RULES FOR JOINS: (1) Join hub to satellite using the hub hash key (e.g. hub_product.product_hk = sat_product_details.product_hk). (2) Join hub to link using the hub hash key (e.g. hub_product.product_hk = lnk_product_location.product_hk). (3) Join link to satellite using the link hash key (e.g. lnk_product_location.product_location_hk = sat_inventory_levels.product_location_hk). (4) Always filter current satellite records with WHERE load_end_dts IS NULL. Please regenerate the populate SQL with correct JOINs.'
  };

  // Call Info Mart Agent again
  const martRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://localhost:5678/webhook/info-mart-agent',
    headers: { 'content-type': 'application/json' },
    body: martRequest,
    json: true,
    timeout: 120000,
  });

  const mart = martRes.mart_table || {};
  const stmts = [];

  // Drop and rebuild
  stmts.push('DROP TABLE IF EXISTS ' + prev.plan.mart_table_name);
  if (mart.ddl) stmts.push(mart.ddl);
  if (mart.populate_sql) mart.populate_sql.split(';').map(s => s.trim()).filter(s => s).forEach(s => stmts.push(s));

  // Execute the new mart SQL
  const execRes = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://duckdb-service:8001/execute-batch',
    headers: { 'content-type': 'application/json' },
    body: { statements: stmts, database: '/data/vault.duckdb' },
    json: true,
    timeout: 60000,
  });

  // Now validate again
  const database = '/data/vault.duckdb';
  const baseUrl = 'http://duckdb-service:8001/query';
  const martName = prev.plan.mart_table_name;

  const countRes = await this.helpers.httpRequest({
    method: 'POST', url: baseUrl,
    headers: { 'content-type': 'application/json' },
    body: { sql: 'SELECT COUNT(*) AS cnt FROM ' + martName, database },
    json: true,
  });
  const rowCount = countRes.rows?.[0]?.cnt || 0;

  let nullCols = [];
  if (rowCount > 0) {
    const sampleRes = await this.helpers.httpRequest({
      method: 'POST', url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql: 'SELECT * FROM ' + martName + ' LIMIT 10', database },
      json: true,
    });
    const rows = sampleRes.rows || [];
    const columns = sampleRes.columns || [];
    for (const col of columns) {
      if (col === 'mart_insert_dts') continue;
      const allNull = rows.every(r => r[col] === null || r[col] === undefined);
      if (allNull && rows.length > 0) nullCols.push(col);
    }
  }

  const valid = rowCount > 0 && nullCols.length === 0;

  return [{ json: { 
    valid, 
    retry_count: retryCount + 1,
    retried: true,
    error: valid ? null : (rowCount === 0 ? 'Still empty after retry' : 'Still has NULL columns after retry: ' + nullCols.join(', ')),
    null_columns: nullCols,
    plan: prev.plan, 
    mart_table: mart,
    vault_tables: prev.vault_tables 
  } }];
})();

