    if (!t || !t.table_name) continue;
    vaultByName[t.table_name] = {
      table_name: t.table_name,
      table_type: t.table_type,
      ddl: t.ddl,
    };
  }

  const existingNames = plan.existing_tables_to_reuse || [];
  const database = '/data/vault.duckdb';
  const baseUrl = 'http://duckdb-service:8001/query';

  function tableTypeFromName(name) {
    if (name.startsWith('hub_')) return 'HUB';
    if (name.startsWith('lnk_')) return 'LINK';
    if (name.startsWith('sat_')) return 'SATELLITE';
    return 'UNKNOWN';
  }

  async function buildPseudoDDL(tableName) {
    const safeName = String(tableName).replace(/'/g, "''");
    const sql =
      "SELECT column_name, data_type FROM information_schema.columns " +
      "WHERE table_schema = 'main' AND table_name = '" + safeName + "' " +
      'ORDER BY ordinal_position;';

    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql, database },
      json: true,
    });

    const cols = res.rows || [];
    if (!cols.length) return null;

    const colDefs = cols.map(c => c.column_name + ' ' + c.data_type).join(', ');
    const ddl = 'CREATE TABLE ' + tableName + ' (' + colDefs + ')';

    return {
      table_name: tableName,
      table_type: tableTypeFromName(tableName),
      ddl,
    };
  }

  const existingVaultTables = await Promise.all(
    existingNames
      .filter(n => n && !vaultByName[n])
      .map(n => buildPseudoDDL.call(this, n))
  );

  for (const t of existingVaultTables) {
    if (t && t.table_name && !vaultByName[t.table_name]) vaultByName[t.table_name] = t;
  }

  const allVault = Object.values(vaultByName);

